// processor-worker/src/index.js
export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);

    if (url.pathname === "/health") {
      return Response.json({ ok: true, service: "processor-worker" });
    }

    if (request.method === "POST" && url.pathname === "/run") {
      let body = {};
      try {
        body = await request.json();
      } catch {}

      const traceId = request.headers.get("x-trace-id") || crypto.randomUUID();
      const userId = request.headers.get("x-user-id") || "anonymous";
      const role = request.headers.get("x-user-role") || "guest";

      const auditReq = new Request("https://internal/audit/log", {
        method: "POST",
        headers: {
          "content-type": "application/json",
          "x-trace-id": traceId,
        },
        body: JSON.stringify({
          event: "process.run",
          userId,
          role,
          payloadSize: JSON.stringify(body).length,
        }),
      });

      ctx.waitUntil(env.AUDIT_SERVICE.fetch(auditReq));

      return Response.json({
        ok: true,
        traceId,
        processedBy: "processor-worker",
        result: {
          receivedInput: body.input ?? null,
          metadata: body.metadata ?? {},
          userId,
          role,
          timestamp: new Date().toISOString(),
        },
      });
    }

    return new Response("Not Found", { status: 404 });
  },
};

